code.Python3:
import sys

def factorial(n:int)->int:
    if n<=1:
        return 1
    return n*factorial(n-1)

def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    N=int(data[0])
    sys.stdout.write(str(factorial(N)))

if __name__=='__main__':
    main()

